var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"저희 프로젝트의 연구기지에 오신 걸 환영합니다, 프리하트 박사님.","JPN":"我がプロジェクトの研究基地へようこそ、プラハト博士。","ENG":"Welcome to our project research lab, Dr. Freeheart.","TWN":"歡迎來到我們專案的研究基地，普立哈特博士。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"안내해줘서 고맙습니다, 장교님.","JPN":"案内ありがとうございます、将校。","ENG":"Thank you for the tour, General.","TWN":"感謝你的介紹，長官。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"깊은 심도의 이면세계에 이렇게 큰 시설을 지을 수 있다니. 경이롭군요.","JPN":"深い裏世界に、こんな大きな施設を建てられるとは。驚きました。","ENG":"It's amazing how such a large facility can be built in the depths of the Counterside.","TWN":"你們竟然能在深度異界裡建造如此龐大的設施，真是太不可思議了。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"북방합의체의 기술력 덕분이죠. 이면세계를 사람이 살 수 있는 곳으로 만들기 위해, 그 어떤 나라보다도 많은 투자를 하고 있으니까요.","JPN":"北方合意体の技術力のおかげです。裏世界を人が住めるようにするため、どの国よりもたくさん投資していますから。","ENG":"It's all thanks to the technological prowess of the Northern Union. It invests more than any other nation to make the Counterside habitable for humans.","TWN":"這要歸功於北方和議會的技術。為了使異界成為人人可以居住的地方，我們投入的資金比其他任何國家都多。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"박사님께서 고문으로 지원해주신 프로젝트도 마찬가지입니다. 프로젝트 셰퍼드는 침식체에게 고통받는 인류의 고충을 덜기 위해 시작된 것이죠.","JPN":"博士が顧問として参加してくださったプロジェクトもそうです。プロジェクト・シェパードは侵食体により苦しむ人類の苦情を減らすために始まったことでしたね。","ENG":"Same goes for the funding of the project you applied to be a consultant on. Project Shepherd was started to alleviate the suffering of humanity from C.O.s.","TWN":"你作為顧問所支援的項目也是如此。牧羊人計畫啟動的目的，就是為了減輕人類因侵蝕體所帶來的痛苦。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"프로젝트의 전반에 대한 설명은 전해 들었습니다.","JPN":"プロジェクト全般についての説明は聞きました。","ENG":"I was informed about the overall project.","TWN":"我已經收到了關於整個專案的詳細介紹。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하지만 기밀유지서약에 사인할 때까지도 연구소가 이면세계에 있는 줄은 몰랐어요.","JPN":"ですが、秘密保持誓約書にサインした時でさえ研究所が裏世界にあるとは思いませんでした。","ENG":"But I didn't know the lab was in the Counterside until I signed the NDA.","TWN":"但在簽署保密協定之前，我並不知道研究所位於異界之中。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"굳이 시설을 이런 곳에 세운 이유가 있는 겁니까?","JPN":"わざわざ施設をこんなところに建てたのは何か理由があるのですか？","ENG":"Is there a reason for building the lab in a place like this?","TWN":"有什麼理由一定要在這種地方建造設施嗎？"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"차차 알게 되시겠지만, 간단히 설명을 드리자면…","JPN":"そのうちおわかりになると思いますが、簡単にご説明しますと……","ENG":"You'll know soon enough, but to briefly explain...","TWN":"你慢慢會了解的，不過簡單來說……"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"저희가 이 프로젝트에서 찾고자 하는 힘의 원류가 이곳에 있기 때문입니다.","JPN":"私たちがこのプロジェクトで調査している力の源がここにあるからです。","ENG":"the power source we are trying to find with this project lies here.","TWN":"因為這裡有我們這個項目所必需的能量源。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"이면세계에 침식체를 통제할 힘이 있다고요?","JPN":"裏世界に侵食体をコントロールする力があるというのですか？","ENG":"There is a way to control C.O.s in the Counterside?","TWN":"什麼？在異界發現了可以控制侵蝕體的力量？"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"저희는 이면세계에서 침식의 영향을 받지 않는 특별한 나무를 찾아냈습니다.","JPN":"私たちは裏世界で侵食にも影響されない特別な木を発見しました。","ENG":"We have found a special tree that is not affected by the Corruption in the Counterside.","TWN":"是的，在這裡，我們發現了一棵不受侵蝕影響的特殊樹木。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"이면세계에 그런 나무가 자라다니… 들어본 적도 없군요.","JPN":"裏世界でそんな木が生えてるなんて……初めて聞きました。","ENG":"A tree growing in the Counterside...? This is the first time hearing it for me.","TWN":"異界竟然會長出那樣的樹木……我從來沒聽說過。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"뿐만 아니라, 그 나무는 한 그루가 온전히 한 세계에만 존재하지 않습니다. 우리가 이곳에서 발견한 건 일부분일 뿐이죠.","JPN":"それだけではなく、その木は一つの世界だけに存在しているわけではありません。私たちがここで発見したのは、ごく一部なのです。","ENG":"Not just that. That tree doesn't exist entirely in just one world. The one we found is only a part of it.","TWN":"而且，那顆樹並不完全存在於一個世界中。我們在這裡發現的只是它其中的一部分。"},"stage":{"bg":"LABORATORY","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하나가 아니라고요? 그게 어떤 의미죠?","JPN":"一本だけではない？　それはどういうことですか？","ENG":"What do you mean it's only a portion of it?","TWN":"不止一個？這表示什麼？"},"stage":{"bg":"LABORATORY","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"그 나무는 땅 속이 아닌 차원계면을 뚫고 자라 있어요. 마치 여러 차원을 넘나들면서 자라온 것처럼.","JPN":"その木は、地面ではなく次元界面を貫き抜けて生えています。まるで、いろんな次元を行き来しているように。","ENG":"That tree grew by digging its roots through the dimension surface and not the ground. It's as if it grew by crossing multiple dimensions.","TWN":"那棵樹不是紮根在地下，而是生長在次元介面當中。就像是跨越了多個次元。"},"stage":{"bg":"LABORATORY","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"저흰 그것을 청동나무로 명명하고 분석하기 시작했습니다.","JPN":"私たちはそれを青銅の木と名づけ、分析を始めました。","ENG":"We have named it the Bronze Tree and have started analyzing it.","TWN":"我們將它命名為青銅樹，並對它展開了分析。"},"stage":{"bg":"LABORATORY","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"그렇다면, 프로젝트 세퍼드도 그 청동나무와 연관이 있는 걸까요?","JPN":"なら、プロジェクト・シェパードもあの青銅の木と関係があるんですか？","ENG":"Then, this Bronze Tree has something to do with Project Shepherd?","TWN":"那麼，牧羊人計畫是否也與青銅樹有關呢？"},"stage":{"bg":"LABORATORY","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"맞습니다. 저희는 바로 그 청동나무로부터 침식에 저항하는 원리를 찾던 중 새로운 에너지를 관측했거든요.","JPN":"そのとおりです。私たちはその青銅の木から侵食に抵抗する原理を調べている途中、新しいエネルギーを観測したのですよ。","ENG":"Correct. While we were researching how the Bronze Tree was able to resist the Corruption, we discovered a new energy source.","TWN":"沒錯。我們在尋找青銅樹抵抗侵蝕的原理的同時，也在過程中觀測到了新能量的產生。"},"stage":{"bg":"LABORATORY","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"조사원들은 그 에너지를 침식체가 극도로 싫어한다는 걸 알게 됐죠.","JPN":"調査員は侵食体がそのエネルギーをとても嫌がってるということに気付きました。","ENG":"And the researchers found out that C.O.s strongly despise this energy.","TWN":"我們的調查人員發現，侵蝕體非常不喜歡這種能量。"},"stage":{"bg":"LABORATORY","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"들어본 적도 없군요. 침식체가 싫어하는 것도 있다니.","JPN":"初めて聞きましたね。侵食体が嫌うものがあるなんて。","ENG":"I've never heard of such a thing. So there are things that C.O.s hate too, huh?","TWN":"我第一次聽說。侵蝕體會有不喜歡的東西。"},"stage":{"bg":"LABORATORY","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"나무에겐 이면세계에서 살아남기 위한 일종의 방어기재 같은 걸까요?","JPN":"木からしたら、裏世界で生き残るためのある種の防衛機制のようなものなんでしょうか？","ENG":"Is this energy a defense mechanism for the tree to survive in the Counterside?","TWN":"這就像是樹木在異界生存的某種防禦機制？"},"stage":{"bg":"LABORATORY","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"그럴 지도 모르죠.","JPN":"そうかもしれません。","ENG":"Perhaps.","TWN":"也許是的。"},"stage":{"bg":"LABORATORY","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"저희는 그 에너지를 분석하는 과정에서 몇 가지 특성을 발견했습니다.","JPN":"私たちはそのエネルギーを分析する過程で、いくつかの特性を発見しました。","ENG":"During our analysis of the energy, we discovered some of its characteristics.","TWN":"在分析這種能量的過程中，我們發現了幾個特性。"},"stage":{"bg":"LABORATORY","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"그 일련의 특성은 박사님의 고국, 노르드나빅의 전승에서 다루던 존재를 닮아있더군요.","JPN":"その一連の特性は博士の母国、ノルドナビックで伝承された存在に似ていたのです。","ENG":"And also that its characteristics seem to resemble those written in the folklore of your home country, Nordnavik.","TWN":"這一系列特性，與博士你的國家，諾爾德萊比傳說中所涉及的存在非常相似。"},"stage":{"bg":"LABORATORY","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"정령.","JPN":"精霊。","ENG":"Elemental.","TWN":"精靈。"},"stage":{"bg":"LABORATORY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"노르드나빅의 전승 속 정령은 사람들을 멋대로 울고 웃게 하며 장난 치는 것을 즐기지.","JPN":"ノルドナビックの伝承に出てくる精霊は、人々を勝手に泣かせたり笑わせたりして遊ぶ。","ENG":"In Nordnavik folklore, Elementals are known for pranking humans and making them laugh or cry at will.","TWN":"在諾爾德萊比的傳說中，精靈喜歡隨心所欲地戲弄人類，是一種讓人又哭又笑的存在。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 위기가 닥치면 정령은 인간을 도와 괴물을 내쫓기도 하는 아주 특별한 존재야.","JPN":"だが危機が迫ると精霊は人間を助け、化け物も追い払う、とても特別な存在だ。","ENG":"But when danger approaches, these Elementals are special entities that help humans chase away monsters.","TWN":"然而，當危機臨近時，精靈卻會幫助人類驅趕怪物。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"북방합의체가 관측한 신 에너지 물질도 그랬어.","JPN":"北方合意体が観測した新エネルギー物質もそうだった。","ENG":"The same goes for the new energy material the Northern Union has observed.","TWN":"北方和議會觀察到的這種新能源物質也一樣。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"파장의 영향을 받은 사람은 감정적으로 돌변하기도 했거든.","JPN":"その波長に影響された人は、突然感情的になったりしたから。","ENG":"Those affected by its wavelengths seem to become emotional.","TWN":"被其波長影響的人類，可能會變得更加情緒化。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"우리는 그것을 스프리건 인자라고 이름 붙였어.","JPN":"僕たちはそれをスプリガン因子と名づけた。","ENG":"We've currently named this Spriggan Factor.","TWN":"我們將其命名為守護者因子。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"스프리건 인자가 주는 영향력은 침식체에게도 유효하다는 걸 알아냈고…","JPN":"スプリガン因子が与える影響は、侵食体にも有効だってことがわかって……","ENG":"This Spriggan Factor also seemed to be effective against C.O.s...","TWN":"因為我們發現，守護者因子的影響似乎對於侵蝕體也有效果……"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체의 감정을 조종할 수 있다면, 인간을 향한 공격성을 억누를 수도 있을 거란 희망이 생겼지.","JPN":"侵食体の感情を操ることができたら、人間への攻撃を抑えることもできるのではないか、という希望ができた。","ENG":"So, if we can emotionally control C.O.s, there is hope for suppressing their aggression toward humans.","TWN":"我們原本預期，如果能夠控制侵蝕體的情緒，就能抑制它對人類的攻擊欲望。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"이 프로젝트가 성공하고 나면, 더는 침식사태의 희생자가 생기지 않을 거라는…","JPN":"このプロジェクトが成功すれば、もうこの侵食によって犠牲者は発生しないだろうという……","ENG":"We arrogantly hoped that... ","TWN":"這個項目成功後，將不再有侵蝕事件的受害者……"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"그런 오만한 기대에 부풀어 있었어.","JPN":"そんな傲慢な期待が膨らんでいた。","ENG":"this project would successfully stop victims of Corruption disasters.","TWN":"我心中曾滿懷著如此大膽的期望。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"남은 과제는 우리가 능동적으로 스프리건 인자를 통제할 방법을 찾는 것.","JPN":"残りの課題は、僕たちが能動的にスプリガン因子を統制する方法を見つけること。","ENG":"The task remaining at hand was to find a way to actively control the Spriggan Factor.","TWN":"目前剩下的任務，是找到一種主動控制守護者因子的方法。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그 답은 사람의 심장에 있었지.","JPN":"そしてその答えは、人間の心臓にあった。","ENG":"And the answer lied in the human heart.","TWN":"而那個答案就在人類的心臟之中。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"스프리건 인자를 끌어들이는 청동나무엔 속씨라는 아주 작은 중추기관이 있는데, 심장이 그것과 비슷했거든.","JPN":"スプリガン因子を引き付ける青銅の木には被子というとても小さな中枢機関があるけど、心臓がそれと似ていたんだ。","ENG":"Within the Bronze Tree, there was a small central organ called the Angiosperm that attracted the Spriggan Factor, and the heart is similar to it.","TWN":"吸引守護者因子的青銅樹上，有一個叫做被子的微型中樞器官，人類的心臟恰巧與它類似。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"문제는… 모든 사람의 심장이 그런 성질을 갖고 있진 않단 거였어.","JPN":"問題は……すべての人間の心臓がそんな性質を持っているわけではないってこと。","ENG":"The problem was... not all human hearts seem to have this property within them.","TWN":"可問題是……並不是所有人的心臟都能適應它。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"113번 후보도 실패했군요.","JPN":"113番も失敗ですね。","ENG":"Candidate No. 113 was also a failure.","TWN":"113號候補也失敗了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"거부반응은 없지만, 색상 분별 테스트에서 떨어졌습니다.","JPN":"拒否反応はありませんが、色分けテストで不合格でした。","ENG":"There were no signs of rejection, but it failed in the color distinguishing test.","TWN":"雖然未產生排斥反應，但沒有通過顏色辨別測試。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"아쉽네요. 하지만 스프리건 인자가 유독 침식환자들에게 거부반응이 낮다는 걸 알아냈으니, 소득이 없는 건 아닙니다.","JPN":"残念です。でもスプリガン因子が特に侵食患者での拒否反応が少ないということがわかったので、少しは成果がありましたね。","ENG":"What a shame. But since we learned that the Spriggan Factor's rejection response is particularly low for patients with Corruption Syndrome, it wasn't a complete waste.","TWN":"太遺憾了。不過，我發現守護者因子唯獨對侵蝕患者的排斥反應特別低，也算是有所收穫。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"침식환자들의 면역결핍이 원인인 걸까요?","JPN":"侵食患者の免疫不全が原因なのでしょうか？","ENG":"Is the cause of that due to the immunodeficiency of Corruption Syndrome patients?","TWN":"是侵蝕患者免疫缺陷的原因嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"통계적으로는 말기환자의 적성률이 높지만, 낮은 연령대에서 색상 분별 테스트를 많이 통과했어요. 단순한 면역력의 문제는 아닌 것 같네요.","JPN":"統計学的には末期患者の適性率が高いですが、若い年代であるほど色分けテストに合格した比率が高いです。単に免疫力の問題ではなさそうですね。","ENG":"Statistically speaking, terminally ill patients seem to have the best response. But younger patients seemed to have a higher rate of passing the color-distinguishing test. So, we believe it's not solely a problem with their immune system.","TWN":"統計顯示，盡管末期患者的適性率更高，但年輕試體有更高的機率通過顏色辨別測試。我認為這不僅僅只是免疫的問題。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"조금 더 시도해보면 곧 적합자를 찾을 수 있을 겁니다.","JPN":"もっと試してみたら、そのうち適合者が見つかるはずです。","ENG":"With more tests, we'll surely find a suitable candidate.","TWN":"再多嘗試幾次，很快就能找到合適的人。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"전 기왕이면 침식환자 중에서 첫번째 적합자가 나왔으면 좋겠네요.","JPN":"できれば侵食患者の中から初の適合者が出てくれたら嬉しいのですが。","ENG":"I personally hope that the first successful case comes from one of the Corruption Syndrome patients.","TWN":"我個人希望第一個合適的候選人會出現在侵蝕患者中。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"침식을 극복하는 스프리건 인자가 시한부 환자들에게 새로운 삶을 줄 테니까요.","JPN":"侵食を克服するスプリガン因子が、余命宣告された患者たちに新しい人生を与えてくれるでしょうから。","ENG":"Because it will give new life to terminal patients as the Spriggan Factor can overcome the Corruption.","TWN":"克制侵蝕的守護者因子，為侵蝕患者帶來嶄新生命，是不是聽起來很美好？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하하… 글쎄요.","JPN":"ハハ……どうですかね。","ENG":"Haha... Perhaps.","TWN":"哈哈……是嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"불치병 환자라고 해서 인자 적응을 위해 몸의 대부분을 의체로 바꾸는 시술을 달가워할지는 잘 모르겠군요.","JPN":"不治の病の患者だとしても、因子適応のために体のほとんどを義体に変える施術を喜んで受け入れるかはわかりませんよ。","ENG":"But I'm not so sure if patients with terminal illnesses will be willing to have most of their bodies replaced with prosthetics just to be able to adapt to the Factor.","TWN":"我不確定這些患者是否願意為了媒合因子，而將身體的大部分換成機械。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"박사님께서 그러셨잖아요? 삶에 대한 집착이 클수록, 시술의 성공률도 높을 거라고요.","JPN":"博士が言ったじゃないですか。人生に執着するほど、施術の成功率も高いはずだって。","ENG":"Wasn't it your words, Doctor? The stronger the will to live, the higher the success rate of the procedure.","TWN":"博士也說過的吧？求生意志越強，手術的成功率就越高。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"죽음을 앞둔 사람만큼 더 절박한 경우가 또 어딨겠어요?","JPN":"死ぬ間際の人より切実なものはないですよ。","ENG":"Who else would be more desperate to live than people on the verge of death?","TWN":"還有什麼比瀕臨死亡，更讓人絕望的呢？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"…그 말씀도 일리가 있네요. 참고할게요.","JPN":"……その言葉も一理ありますね。参考にします。","ENG":"...That also makes sense. I'll keep that in mind.","TWN":"……你說的有道理。我記住了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"오늘은 이쯤에서 정리하도록 하죠.","JPN":"今日はこの辺にしましょう。","ENG":"Let's call it a day for today.","TWN":"今天就到這裡吧。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RESEARCHER_FLOOR_CIVIL_ASSIST","text":{"KOREA":"여기요. 떠나기 전에 송신기 챙기세요.","JPN":"はい。出る前に送信機を。","ENG":"Here. Make sure to take your transmitter before you go.","TWN":"博士，離開前，請你帶上發射器。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_CIVIL_ASSIST","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"매번 이런 걸 달고 있어야 하는 건가요?","JPN":"いつもこんなものをつけていないといけないんですか？","ENG":"Do I have to carry this around every time?","TWN":"我每次都必須帶上這個東西嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_CIVIL_ASSIST","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RESEARCHER_FLOOR_CIVIL_ASSIST","text":{"KOREA":"아시잖아요. 프로젝트 보안규정상 어쩔 수 없는 거.","JPN":"わかるでしょう？　プロジェクトの規定上、仕方ないことだって。","ENG":"You have to. It's because of the project's security regulations.","TWN":"你也知道。為了項目安全著想，這也是沒辦法的事。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_CIVIL_ASSIST","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하아… 알겠습니다.","JPN":"はあ……わかりました。","ENG":"*Sigh...* I understand.","TWN":"唉……好吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_CIVIL_ASSIST","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RESEARCHER_FLOOR_CIVIL_ASSIST","text":{"KOREA":"휴가는 고향에 가실 건가요?","JPN":"休みの日は里帰りですか？","ENG":"Are you going home for vacation?","TWN":"你這次是回家鄉度假嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_CIVIL_ASSIST","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"아뇨, 병원으로 갈 겁니다. 제 가족은 그곳에 있으니까요.","JPN":"いいえ、病院です。家族がいますから。","ENG":"No, I'm heading to the hospital. My family is there.","TWN":"不，我要去醫院。我的家人都在那裡。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_CIVIL_ASSIST","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"딸에게 한창 아빠 노릇해줄 시기인데, 최근엔 목소리도 거의 못들려줬거든요.","JPN":"娘に父親としての務めを果たすべき時期なのに、最近は声すらもまともに聞かせてやれなくて。","ENG":"I should be a good father to my daughter, but lately, I've barely even talked to her.","TWN":"我本來應該當好一個爸爸的，但最近，我幾乎連女兒的面都見不到。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_CIVIL_ASSIST","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"앗, 아빠다!","JPN":"あっ、お父さん！","ENG":"Oh! It's Daddy!","TWN":"啊，爸爸！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"많이 기다렸지? 늦어서 미안하구나.","JPN":"お待たせ。遅くなってごめんな。","ENG":"Sorry I'm late. Did you wait long for me?","TWN":"等很久了吧？對不起，我來晚了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"엄마는 일이 바빠서 오늘 못 온대요.","JPN":"お母さんは忙しくて今日来れないんだって。","ENG":"Mommy said she was busy so she can't come today.","TWN":"媽媽說她工作很忙，今天來不了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"그래? 그럼 아빠랑 밖에 나가서 놀까?","JPN":"そうか。じゃあ、お父さんと外で遊ぶか？","ENG":"Oh, really? Then do you wanna go out with Daddy?","TWN":"是嗎？那要不要和爸爸一起出去玩？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"그치만 엄마가 나 다친다고 병원 나가지 말랬는데.","JPN":"でも、お母さんが怪我するから病院から出ちゃダメって言ってたよ。","ENG":"But Mommy told me not to go outside until I'm all better.","TWN":"可是，媽媽說我受傷了，不讓我離開醫院。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"괜찮아. 오늘은 날씨가 좋으니까. 따뜻하게 입고 놀이공원 가자.","JPN":"大丈夫。今日は天気がいいから。暖かい服を着て遊園地に行こう。","ENG":"It's okay. The weather's nice out today. Let's wear something warm and play in the park.","TWN":"沒關係。今天天氣好，我們穿暖和點去遊樂園吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"오예-!","JPN":"わーい！","ENG":"Yipee!","TWN":"好耶——！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"후아, 엄청 재밌었다.","JPN":"はあ、本当に楽しかった。","ENG":"Huah! That was so much fun.","TWN":"哇，真有趣。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"윽- 그리고 멀미 나.","JPN":"ううっーだけど酔っちゃいそう。","ENG":"Ngh... And I'm feeling nauseous.","TWN":"呃——我有些頭暈。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하하, 마지막에 롤러코스터만 두 번이나 탔으니까.","JPN":"はは、最後に2回もジェットコースターに乗ったからな。","ENG":"Haha! That's because you rode the rollercoaster twice in a row.","TWN":"哈哈，那是因為你最後連坐了兩次雲霄飛車。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"곧 불꽃놀이 할 시간이네. 해변으로 갈까?","JPN":"もうすぐ花火の時間だ。海辺に行こうか？","ENG":"It's almost time for the fireworks. Want to head to the beach?","TWN":"馬上就要放煙火了。我們去海邊吧？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"응! 좋아!","JPN":"うん！　やったー！","ENG":"Uh-huh! The beach!","TWN":"嗯！好！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"우와, 엄청 예쁘다. 저 불꽃 모양 좀 봐!","JPN":"わあ、すごくキレイ。あの花火、見て！","ENG":"Wow! It's so pretty. Look at that firework!","TWN":"哇，好漂亮。快看那些煙火！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"우리 딸이 불꽃놀이를 이렇게 좋아할 줄 알았으면 아빠가 앞으로도 자주 보여줘야겠네.","JPN":"こんなに花火好きだったなんて、お父さんがこれからもたくさん見せてあげないとな。","ENG":"Since you like fireworks so much, Daddy will take you out to see them more from now on.","TWN":"既然你這麼喜歡煙火，爸爸以後經常帶你來看好不好？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"정말? 그럼 매일 같이 놀러가는 거야?","JPN":"本当？　じゃあ、毎日一緒に遊びに行ってくれるの？","ENG":"Really? Then, are we going out to play every day now?","TWN":"真的嗎？那我們每天都可以一起出去玩嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"그래.","JPN":"もちろん。","ENG":"Yeah.","TWN":"可以。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"병원에서 지내는 거 불편하다고 했지?","JPN":"病院はつまらないって言ってただろう？","ENG":"It's uncomfortable staying all day inside the hospital, right?","TWN":"你不是說過不喜歡待在醫院嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"아빠 일이 끝나면, 더 좋은 곳으로 이사 가자.","JPN":"お父さんの仕事終わったら、もっといいところに引っ越ししよう。","ENG":"Once Daddy's work is done, let's move somewhere better.","TWN":"等爸爸的工作結束了，我們就搬到一個更好的地方去吧。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"이사…?","JPN":"引っ越し……？","ENG":"Move...?","TWN":"搬家……？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"그래, 불꽃놀이가 보이는 바닷가에 큰 집을 사고 의사도 집으로 부르는 거야.","JPN":"そう、花火が見える海辺に大きな家を建てて、医者にも家に来てもらうんだ。","ENG":"Yeah. Daddy will buy a home on the beach where you can watch all the fireworks you want and have doctors come over.","TWN":"嗯，我們在海邊買一棟可以看煙火的大房子，再把醫生叫回家。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"그럼 더 이상 병원에서 지내지 않아도 돼.","JPN":"そうしたら、もう病院にいなくてもいいだろう？","ENG":"That way, you won't have to spend any more time at hospitals.","TWN":"這樣你就不用再待在醫院了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"음…","JPN":"うーん……","ENG":"Mm...","TWN":"唔……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"병원에 있는 건 괜찮아. 아플 땐 병원에 있어야 낫는 거니까.","JPN":"病院にいるのは大丈夫。病気の時には、病院にいなきゃ治らないし。","ENG":"I don't mind staying at the hospital. It's where people go to get better when they’re sick.","TWN":"在醫院也沒關係。生病的時候，待在醫院才能好起來。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"그냥… 나 입원한 뒤로는 아빠 엄마를 자주 못 봐서, 그게 싫었어.","JPN":"ただ……私が入院した後からお父さんとお母さんとよく会えなくて、それが嫌だった。","ENG":"I just... didn't like how Mommy or Daddy wouldn't visit as much after staying there. That's what I didn't like.","TWN":"只是……我住院後，就不能經常見到爸爸媽媽，我很討厭這樣。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"있지, 딸.","JPN":"あのね。","ENG":"Hey, sweet pea.","TWN":"我的女兒。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"아빠 일 끝나고 나면, 여유가 좀 생기거든.","JPN":"お父さんの仕事が終ったら、ちょっと暇ができるんだよ。","ENG":"Daddy will be free after I finish my work.","TWN":"爸爸的工作結束之後，就能有時間陪你了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"그땐 엄마도 같이 가족여행이나 갈까? 이렇게 다 같이 불꽃놀이도 구경하고.","JPN":"その時にお母さんも一緒に家族旅行に行かないか？　こうやって、みんなで花火も見て。","ENG":"How about we go on a family trip after with Mommy? And we can all go see some fireworks.","TWN":"那個時候，我們就可以和媽媽一起去家家族行？還能一起看煙火。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"정말? 나 가족여행 가고 싶어! 정말로 가는 거지?","JPN":"本当？　私、家族旅行行きたい！　本当に行くんだよね？","ENG":"Really? I wanna go on a family trip! Are we really going to?","TWN":"真的嗎？我想去家族旅行！真的會去的吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"그래, 약속해.","JPN":"ああ、約束するよ。","ENG":"Yeah. I promise.","TWN":"是的，我保證。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"어…?","JPN":"あれっ……？","ENG":"Huh...?","TWN":"唔……？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"아빠 주변이… 빨갛게 빛나고 있어.","JPN":"お父さんの周りが……赤く光ってる。","ENG":"Daddy... things around you are starting to glow red.","TWN":"爸爸周圍……在閃著紅光。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하하, 폭죽 때문에 그런 거겠지.","JPN":"ハハッ、きっと花火のせいだろう？","ENG":"Haha, that's because of the fireworks.","TWN":"哈哈，一定是因為煙火吧。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"아니야. 조금이지만 병실에 있을 때도 아빠 주위에 빨간색이 보였는걸?","JPN":"ううん。ちょっとだけ、それに病室にいた時にもお父さんの周りに赤い色が見えたもん。","ENG":"No. I saw it before at the hospital too. Things around you were a little red then too.","TWN":"不是。雖然只有一點點，但我在醫院的時候，也看到過。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"이제 돌아갈까? 우리 딸, 감기 걸리면 아빠가 혼날 테니까.","JPN":"もう帰ろう。　風邪ひくと、お父さんが怒られちゃうから。","ENG":"Shall we head back now? Daddy will get scolded if you catch a cold.","TWN":"我們現在回去吧？如果我的女兒感冒了，爸爸會挨駡的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"으으, 춥다. 빨리 들어가자.","JPN":"ううっ、寒い。早く帰ろう。","ENG":"Ooh... It's cold. Let's go in.","TWN":"呃呃，好像真的有些冷耶。我們快點回去吧。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"스프리건 입자가 일반인의 몸에 달라붙기도 하는군요. 다음부턴 출입문에 탐지기라도 세워야겠어요.","JPN":"スプリガン因子が一般人の体にくっつくこともあるんですね。次からは出入口に探知機でも設置しないと。","ENG":"The Spriggan particles also seem to stick to ordinary people too. We'll have a detector set up at the entrance next time.","TWN":"守護者因子還會附著在普通人的身體上啊。看來下次得在門口裝個探測器了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"연구 중인 인자의 존재가 현실에 유출됐다간 관리국이 우리 프로젝트를 통제하려고 할 테니까요.","JPN":"研究している因子の存在がノーマルサイドに流出されると、管理局がこのプロジェクトを統制してくるはずですから。","ENG":"If the Factor gets leaked into the Normalside, the Administration will try to control our project.","TWN":"如果正在研究中的因子被洩露到現實中，管理局將會對我們的項目進行管制。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"미안합니다. 제가 잘 확인했어야 하는데.","JPN":"すみません。僕がちゃんと確認すべきでした。","ENG":"My apologies. I should've checked before leaving.","TWN":"抱歉。我應該仔細檢查的。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"빨간색을 봤다면서요?","JPN":"赤い色を見たんですよね？","ENG":"You said your daughter saw red?","TWN":"不過，你說她看到了紅色？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"예…?","JPN":"はい……？","ENG":"Excuse me...?","TWN":"嗯……？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"감정변화에 반응하는 스프리건 입자가 붉게 보일수록 인자 적합성이 높은 거잖아요.","JPN":"感情の変化に反応するスプリガン因子が赤く見えるほど、因子の適合性が高いんでしょう？","ENG":"Spriggan particles react to emotional changes. The redder they appear, the more suitable of a candidate they are.","TWN":"守護者因子會對情緒變化做出反應，能看到的越紅，說明因子適應性也越高。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"안 그런가요?","JPN":"違いますか？","ENG":"Isn't that so?","TWN":"不是嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"제 딸을 이 실험에 끌어들일 생각은 없습니다.","JPN":"僕の娘をこの実験に関与させるつもりはありません。","ENG":"I have no intention of involving my daughter in this experiment.","TWN":"我不打算讓女兒參加這個實驗。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"아시다시피 지원자가 아니라면 강요하지 않아요, 박사님.","JPN":"ご存知のように、志願者でなければ無理強いはしません、博士。","ENG":"As you know, we won't force you to do anything, Doctor.","TWN":"你知道的，我們不會強迫任何非應聘者，博士。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"하지만 앞일이란 건, 어떻게 될지 모르는 거잖아요?","JPN":"しかしこの先、どうなるかわかりませんよ？","ENG":"But no one knows what the future holds, right?","TWN":"但將來的事，誰又能說得准呢？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그 뒤로 여유가 있을 때마다 불꽃놀이가 유명한 관광지를 찾아봤어.","JPN":"その後、合間を縫って花火が有名な観光地を調べた。","ENG":"After that day, I looked for famous tourist spots for fireworks whenever I had the time.","TWN":"在那之後，我一有空閒，就會去搜索有名的煙火景點。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 다음 휴가 때 팜플렛을 들고 병원을 찾았는데, 딸아이는 말을 하지 못하는 상태였지.","JPN":"そして次の休みの時にパンフレットを持って病院に行くと、娘は何も喋れない状態だった。","ENG":"On one of my days off, I brought a brochure to the hospital, but my daughter couldn't even speak.","TWN":"等我再次休假，拿著旅遊手冊去醫院時，女兒卻已經無法開口說話了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"하루에 몇 번씩이나 발작을 하고, 당신을 알아보지 못해 밀쳐냈어.","JPN":"一日に何度も発作を起こして、君が誰かわからず拒否した。","ENG":"She would have seizures several times a day, and push you away because she couldn't recognize you.","TWN":"她一天會發作好幾次，並因為忘記了你而把你推開。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"맛을 잃고, 식욕도 잃었어. 발목 아래로는 마비가 와서 걷지도 못하게 됐고.","JPN":"味覚を失い、食欲もなくなった。足首の下が麻痺して、歩くこともできなくなった。","ENG":"She lost her sense of taste, appetite, and couldn't walk due to being paralyzed from the ankle down.","TWN":"她失去了味覺和食慾。腳踝以下因為麻痹而無法行走。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"의사에게 안락사 권유를 받은 뒤로, 당신은 괴로워하는 아이 곁에서 밤을 지새우며 나날이 초췌해졌지.","JPN":"医者から安楽死をすすめられてから、君は苦しむあの子を徹夜で介護して、日に日にやつれていった。","ENG":"After the doctors suggested euthanasia, you would stay by her side all day and night, growing haggard with each passing day.","TWN":"醫生給出的建議是安樂死，那之後你日日夜夜陪在受苦的孩子身邊，一天比一天憔悴。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>선택</color>을 해야 한다고 생각했어.","JPN":"<color=#ffd34c>選択</color>が必要だと思ったんだ。","ENG":"I thought I had to make <color=#ffd34c>a choice</color>.","TWN":"我想我該做出<color=#ffd34c>選擇</color>了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"더는 돌이킬 수 없게 되기 전에 말이야.","JPN":"もう取り返しが付かなくなる前に。","ENG":"Before it was too late.","TWN":"在徹底無法挽回之前。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};